import React from "react";
import styles from "./product.module.css";
import GridLayout from "../layout/grid-layout";
import ProductPresentation from "./product-presentation";
import ProductInfo from "./product-info";
import { useParams } from "react-router-dom";
import products from '../nav-list/nav-list.json';

// Define the type for a product
interface ProductProps {
  id: number;
  name: string;
  price: number;
  img: string;
  productId: s
}

const Product: React.FC<ProductProps> = () => {
  const { productId } = useParams<{ productId: string }>(); // Specify the type of productId
  const product: Product | undefined = products.find((product) => product.id === parseInt(productId));

  if (!product) {
    // Handle the case where the product is not found, for example, display an error message or redirect.
    return <div>Product not found</div>;
  }

  // Destructure the productData object to access img, price, and name
  const { img, price, name } = product;

  return (
    <div className={styles.product}>
      <div className="container">
        <GridLayout>
          <div className="left-side">
            <ProductPresentation imgSrc={img} />
          </div>
          <div className={styles.right_side}>
            <ProductInfo name={name} price={price} />
          </div>
        </GridLayout>
      </div>
    </div>
  );
};

export default Product;


